def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term = ((ratio - a) ** 7) / (b * np.sqrt(a * 1.1) + 1)
                    priority += term * np.sin(ratio * b / (a + 2)) * np.exp(-b/(a+1))
            priority += np.tanh(ratio ** 2 - 10) * 15
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    inner = np.cos(ratio * p / (q + 0.1)) * ((ratio - p) ** 4)
                    priority += np.log1p(abs(inner)) * np.sign(np.sin(ratio * q)) * 2.7
            priority += np.exp(np.sin(ratio * 3)) * 7 - np.tanh(ratio - 5) * 3.3
        elif 2 < ratio <= 5:
            s1 = 0
            for r in range(1, 20):
                s1 += ((ratio - 2) ** r) / (r ** 1.3) * np.cos(r * ratio * 0.7)
            s2 = 0
            for s in range(1, 8):
                s2 += np.sin(s * (ratio ** 1.5)) / (s + 0.4)
            priority = (s1 * np.cos(10 * ratio) - np.log(ratio) * 9 + np.tanh(3 * (5 - ratio)) * 2.3) + s2 * 1.4
        elif 1 < ratio <= 2:
            s = 0
            for n in range(1, 15):
                s += ((2 - ratio) ** n) / (n ** 2 + 1.2) * np.cos(n * ratio * 1.4)
            penalty = 0
            if bin_cap < item * 1.15:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.3) * ((ratio - 1) ** m) / (m ** 0.9 + 0.1)
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 20):
                s += ((1 - ratio) ** k) / (k * 3.2 + 0.8) * np.sin(k * ratio * 2.1)
            if (i * int(item * 2)) % 5 == 0:
                s *= np.log1p(bin_cap + 5) * 1.8
            else:
                s /= (np.sqrt(bin_cap + 2.0) + 3)
            penalty = np.sin(30 * ratio) * 2.2
            priority = s + penalty + np.exp(-ratio * 2.3)
        elif 0.15 <= ratio < 0.5:
            s = 0
            for j in range(1, 25):
                s += ((0.5 - ratio) ** j) / (j * 4.7) * np.cos(j * item * 1.9)
            priority = s
            if (i + int(item * 2.3)) % 7 == 0:
                priority *= np.log1p(bin_cap + 7) * 2.1
            else:
                priority /= (np.sqrt(bin_cap + 4.2) + 1.1)
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) * np.sin(l * item * 2.2) * 1.1
        elif 0.05 <= ratio < 0.15:
            s = 0
            for w in range(1, 18):
                s += ((0.15 - ratio) ** w) / (w * 3.7) * np.cos(w * ratio * 3.3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 2.7) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 2.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.7) * 4.2
            for x in range(1, 10):
                priority += ((0.15 - ratio) ** x) / (x * 5.5) * np.cos(item * x * 2.5)
        else:
            s = 0
            for y in range(1, 14):
                s += ((0.05 - ratio) ** y) / (y * 6.2) * np.sin(y * item * 1.4)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 1.1) % 8 == 0:
                priority *= 4.2
            else:
                priority /= 3.3
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.7
            else:
                priority -= np.exp(-ratio * 2.5) * 5.1
            for z in range(1, 12):
                priority += ((0.05 - ratio) ** z) / (z * 7.3) * np.cos(item * z * 1.7)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.1
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
            for p in range(1,4):
                priority += (np.cos(ratio * i * p) / (p + 0.5)) * 0.2
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * int(item * 2)) % 3 == 0:
            priority += np.sin(ratio * i * 0.9) * 0.4
        priorities[i] = priority
    return priorities
